import React from 'react'
import PropTypes from 'prop-types'

//Use border on all variations to enforce consistent sizing
const baseCSS = 'py-2 px-4 rounded-lg border flex items-center'

//Tailwind uses PurgeCSS
const variations = {
  contained: {
    primary:
      'border-transparent bg-primary-900 text-slate-50 dark:bg-primary-50 dark:text-slate-900 focus:outline-primary-900/30 dark:focus:outline-primary-50/30 focus:outline focus:outline-offset-2',
  },
  outline: {
    primary:
      'dark:text-slate-50 dark:border-primary-50 border-primary-900 text-slate-900 focus:outline-primary-900/30 dark:focus:outline-primary-50/30 focus:outline',
    inherit: 'border-inherit',
  },
  text: {
    primary: 'dark:text-slate-50 text-slate-900 border-transparent active:bg-zinc-900/10 hover:bg-slate-900/5',
    inherit: 'text-inherit',
  },
}

const sizes = {
  sm: 'py-1 px-3 text-xs',
  md: 'py-2 px-6 text-sm',
}

export const Button = React.forwardRef(
  (
    { component = 'button', color = 'primary', size = 'md', children, variant = 'text', className = '', ...props },
    ref
  ) => {
    return React.createElement(
      component,
      {
        ref: ref,
        className: `font-medium ${baseCSS} ${sizes[size]} ${variations[variant][color]} ${className ?? ''}`.trim(),
        ...props,
      },
      children
    )
  }
)
Button.displayName = 'Button'

Button.propTypes = {
  component: PropTypes.oneOf(['button', 'a']),
  class: PropTypes.string,
  className: PropTypes.string,
  color: PropTypes.oneOf(['inherit', 'primary']),
  variant: PropTypes.oneOf(['outline', 'contained', 'text']),
  children: PropTypes.node,
  size: PropTypes.oneOf(Object.keys(sizes)),
}
