import React, { useState } from 'react'
import PropTypes from 'prop-types'

//Use border on all variations to enforce consistent sizing
const baseCSS = 'bg-white ring-primary py-2 px-4 rounded-lg border items-center inline-flex gap-1'

export const Textbox = React.forwardRef(
    (
        {
            suffix,
            prefix,
            focusClassName = '',
            inputProps: { className: inputClassName } = {},
            className = '',
            onFocus,
            onBlur,
            ...restProps
        },
        ref
    ) => {
        const [isFocused, setIsFocused] = useState(false)
        const handleFocus = (e) => {
            setIsFocused(true)
            onFocus?.(e)
        }
        const handleBlur = (e) => {
            setIsFocused(false)
            onBlur?.(e)
        }
        return (
            <div
                className={`${baseCSS} ${className} ${
                    isFocused ? `outline outline-primary-800 ${focusClassName ?? ''}` : ''
                }`}
            >
                {!!prefix && <>{prefix}</>}
                <input
                    onFocus={handleFocus}
                    onBlur={handleBlur}
                    className={`bg-inherit focus:border-none focus:outline-none flex-auto ${inputClassName ?? ''}`}
                    ref={ref}
                    {...restProps}
                />
                {!!suffix && <>{suffix}</>}
            </div>
        )
    }
)
Textbox.displayName = 'Textbox'
Textbox.propTypes = {
    className: PropTypes.string,
    focusClassName: PropTypes.string,
    children: PropTypes.node,
    onFocus: PropTypes.func,
    onBlur: PropTypes.func,
    suffix: PropTypes.node,
    prefix: PropTypes.node,
    inputProps: PropTypes.object,
}
